// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IPayable {
  function debt(address target) external view returns (uint256);
}

contract ValcoreReactiveDispatcher {
  error InvalidAddress();
  error Unauthorized();

  event Callback(uint256 indexed chain_id, address indexed _contract, uint64 indexed gas_limit, bytes payload);
  event OperatorUpdated(address indexed previousOperator, address indexed newOperator);

  IPayable public constant SERVICE_ADDR = IPayable(0x0000000000000000000000000000000000fffFfF);

  uint256 public immutable destinationChainId;
  address public immutable destinationReceiver;
  address public operator;

  mapping(address => bool) private _authorizedSenders;

  constructor(uint256 targetChainId, address targetReceiver, address initialOperator) payable {
    if (targetChainId == 0 || targetReceiver == address(0) || initialOperator == address(0)) {
      revert InvalidAddress();
    }

    destinationChainId = targetChainId;
    destinationReceiver = targetReceiver;
    operator = initialOperator;

    _authorizedSenders[address(SERVICE_ADDR)] = true;
    emit OperatorUpdated(address(0), initialOperator);
  }

  receive() external payable {}

  modifier onlyOperator() {
    if (msg.sender != operator) revert Unauthorized();
    _;
  }

  modifier authorizedSenderOnly() {
    if (!_authorizedSenders[msg.sender]) revert Unauthorized();
    _;
  }

  function setOperator(address newOperator) external onlyOperator {
    if (newOperator == address(0)) revert InvalidAddress();
    address previous = operator;
    operator = newOperator;
    emit OperatorUpdated(previous, newOperator);
  }

  function dispatch(bytes calldata payload, uint64 gasLimit) external onlyOperator {
    emit Callback(destinationChainId, destinationReceiver, gasLimit, payload);
  }

  function pay(uint256 amount) external authorizedSenderOnly {
    _pay(payable(msg.sender), amount);
  }

  function coverDebt() external {
    uint256 amount = SERVICE_ADDR.debt(address(this));
    _pay(payable(address(SERVICE_ADDR)), amount);
  }

  function withdraw(address payable recipient, uint256 amount) external onlyOperator {
    if (recipient == address(0)) revert InvalidAddress();
    _pay(recipient, amount);
  }

  function _pay(address payable recipient, uint256 amount) internal {
    require(address(this).balance >= amount, "Insufficient funds");
    if (amount > 0) {
      (bool ok,) = recipient.call{value: amount}("");
      require(ok, "Transfer failed");
    }
  }
}

